input.script:
import { execution } from '@dynatrace-sdk/automation-utils';


export default async function ({ execution_id }) {
  const exec = await execution(execution_id);

  const ex = await fetch(`/platform/automation/v1/executions/${execution_id}`);
  const data = await ex.json();
  const event = data.params?.event || {};
  const problemTitle = event['event.name'] || 'Unknown problem';
  const problemId = event['event.id'] || 'N/A';
  const status = event['event.status'] || 'OPEN';
  const affectedEntities = (event['affected_entity_ids'] || []).join(', ') || 'N/A';
  const rootCause = event['root_cause_entity_name'] || 'Unknown';
  const startTime = event['event.start'] || new Date().toISOString();
  const dtUrl = event['dt.davis.mute_url']?.replace('/mute', '') || '';
  const deployment = await exec.result('execute_dql_query_1');
  console.log(deployment.records[0]["lookup.deployment.url"])

  return {
    deploymentUrl: deployment.records[0]["lookup.deployment.url"],
    problemTitle,
    problemId,
    status,
    affectedEntities,
    rootCause,
    startTime,
    dtUrl
  };
}

